def shortest_word(s):
    if not s:
        return ''

    words = s.split()
    shortest = min(words, key=len, default='')

    # Find the last word with the minimum length
    max_len = len(shortest)
    for i in range(len(words) - 1, -1, -1):
        if len(words[i]) == max_len:
            return words[i]
